// mockTransformer is a test implementation of the Transformer interface
// that can be configured to simulate various encryption/decryption behaviors
type mockTransformer struct {
	encryptFunc func(ctx context.Context, data []byte) ([]byte, error)
	decryptFunc func(ctx context.Context, data []byte) ([]byte, bool, error)
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.encryptFunc != nil {
		return m.encryptFunc(ctx, data)
	}
	// Default: simple XOR transformation for testing
	result := make([]byte, len(data))
	for i, b := range data {
		result[i] = b ^ 0xFF
	}
	return result, nil
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.decryptFunc != nil {
		return m.decryptFunc(ctx, data)
	}
	// Default: reverse the XOR transformation
	result := make([]byte, len(data))
	for i, b := range data {
		result[i] = b ^ 0xFF
	}
	return result, false, nil
}

// TestDefaultContext verifies the DefaultContext implementation
func TestDefaultContext(t *testing.T) {
	data := []byte("test-context-data")
	ctx := DefaultContext(data)

	if got := ctx.AuthenticatedData(); !bytes.Equal(got, data) {
		t.Errorf("AuthenticatedData() = %q, want %q", got, data)
	}
}

// TestDefaultContextNil verifies DefaultContext with nil data
func TestDefaultContextNil(t *testing.T) {
	var ctx DefaultContext
	if got := ctx.AuthenticatedData(); got != nil {
		t.Errorf("AuthenticatedData() = %q, want nil", got)
	}
}

// TestDefaultContextEmpty verifies DefaultContext with empty data
func TestDefaultContextEmpty(t *testing.T) {
	ctx := DefaultContext([]byte{})
	if got := ctx.AuthenticatedData(); !bytes.Equal(got, []byte{}) {
		t.Errorf("AuthenticatedData() = %q, want empty byte slice", got)
	}
}

// TestTransformerRoundTrip verifies that a transformer can encrypt and decrypt data correctly
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name     string
		original []byte
	}{
		{"simple text", []byte("hello world")},
		{"empty data", []byte("")},
		{"binary data", []byte{0x00, 0x01, 0x02, 0xFF}},
		{"large data", bytes.Repeat([]byte("test"), 1000)},
		{"special characters", []byte("!@#$%^&*()_+-=[]{}|;:',.<>?/")},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{}
			ctx := context.Background()

			// Encrypt
			encrypted, err := transformer.TransformToStorage(ctx, tt.original, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Decrypt
			decrypted, stale, err := transformer.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if stale {
				t.Errorf("stale = true, want false for fresh data")
			}

			if !bytes.Equal(decrypted, tt.original) {
				t.Errorf("decrypted = %q, want %q", decrypted, tt.original)
			}
		})
	}
}

// TestTransformerWithContext verifies that transformers receive the context correctly
func TestTransformerWithContext(t *testing.T) {
	encryptCalled := false
	decryptCalled := false
	passedCtx := context.WithValue(context.Background(), "key", "value")

	transformer := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			encryptCalled = true
			if ctx.Value("key") != "value" {
				t.Error("context not properly passed to encrypt function")
			}
			return data, nil
		},
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			decryptCalled = true
			if ctx.Value("key") != "value" {
				t.Error("context not properly passed to decrypt function")
			}
			return data, false, nil
		},
	}

	transformer.TransformToStorage(passedCtx, []byte("test"), nil)
	if !encryptCalled {
		t.Error("encrypt function was not called")
	}

	transformer.TransformFromStorage(passedCtx, []byte("test"), nil)
	if !decryptCalled {
		t.Error("decrypt function was not called")
	}
}

// TestTransformerErrorPropagation verifies that errors are properly propagated
func TestTransformerErrorPropagation(t *testing.T) {
	tests := []struct {
		name           string
		encryptErr     error
		decryptErr     error
		expectEncError bool
		expectDecError bool
	}{
		{"encryption error", fmt.Errorf("encrypt failed"), nil, true, false},
		{"decryption error", nil, fmt.Errorf("decrypt failed"), false, true},
		{"both fail", fmt.Errorf("encrypt failed"), fmt.Errorf("decrypt failed"), true, true},
		{"no error", nil, nil, false, false},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
					return nil, tt.encryptErr
				},
				decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
					return nil, false, tt.decryptErr
				},
			}
			ctx := context.Background()

			_, encErr := transformer.TransformToStorage(ctx, []byte("test"), nil)
			if (encErr != nil) != tt.expectEncError {
				t.Errorf("TransformToStorage error = %v, want error = %v", encErr, tt.expectEncError)
			}

			_, _, decErr := transformer.TransformFromStorage(ctx, []byte("test"), nil)
			if (decErr != nil) != tt.expectDecError {
				t.Errorf("TransformFromStorage error = %v, want error = %v", decErr, tt.expectDecError)
			}
		})
	}
}

// TestTransformerStaleDataMarking verifies that stale data is properly marked
func TestTransformerStaleDataMarking(t *testing.T) {
	tests := []struct {
		name          string
		staleExpected bool
		decryptFunc   func(ctx context.Context, data []byte) ([]byte, bool, error)
	}{
		{
			name:          "fresh data",
			staleExpected: false,
			decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
				return data, false, nil
			},
		},
		{
			name:          "stale data",
			staleExpected: true,
			decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
				return data, true, nil
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{
				decryptFunc: tt.decryptFunc,
			}
			ctx := context.Background()

			_, stale, err := transformer.TransformFromStorage(ctx, []byte("test"), nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if stale != tt.staleExpected {
				t.Errorf("stale = %v, want %v", stale, tt.staleExpected)
			}
		})
	}
}

// TestPrefixTransformerBehavior verifies PrefixTransformer struct properties
func TestPrefixTransformerBehavior(t *testing.T) {
	tests := []struct {
		name           string
		prefix         []byte
		transformerErr error
		expectMatch    bool
	}{
		{"matching prefix", []byte("k8s:enc:aes:"), nil, true},
		{"empty prefix", []byte(""), nil, true},
		{"long prefix", []byte("prefix-that-is-quite-long"), nil, true},
		{"transformer with error", []byte("error:"), fmt.Errorf("test error"), true},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{}
			prefixTrans := PrefixTransformer{
				Prefix:      tt.prefix,
				Transformer: transformer,
			}

			if prefixTrans.Transformer == nil {
				t.Error("Transformer field should not be nil")
			}

			if !bytes.Equal(prefixTrans.Prefix, tt.prefix) {
				t.Errorf("Prefix = %q, want %q", prefixTrans.Prefix, tt.prefix)
			}
		})
	}
}

// TestNewPrefixTransformersWithNoTransformers verifies behavior with empty transformers list
func TestNewPrefixTransformersWithNoTransformers(t *testing.T) {
	testErr := fmt.Errorf("no matching prefix")
	transformer := NewPrefixTransformers(testErr)

	ctx := context.Background()
	_, _, err := transformer.TransformFromStorage(ctx, []byte("data"), nil)
	if err == nil {
		t.Error("TransformFromStorage should return error when no transformers match")
	}
	if err != testErr {
		t.Errorf("error = %v, want %v", err, testErr)
	}
}

// TestNewPrefixTransformersDefaultError verifies default error when none provided
func TestNewPrefixTransformersDefaultError(t *testing.T) {
	transformer := NewPrefixTransformers(nil)

	ctx := context.Background()
	_, _, err := transformer.TransformFromStorage(ctx, []byte("unknown"), nil)
	if err == nil {
		t.Error("TransformFromStorage should return error")
	}

	// The error message should mention transformer matching
	if err.Error() != "the provided value does not match any of the supported transformers" {
		t.Errorf("unexpected error message: %v", err)
	}
}

// TestPrefixTransformerPrefixHandling verifies prefix removal during transformation
func TestPrefixTransformerPrefixHandling(t *testing.T) {
	tests := []struct {
		name         string
		prefix       []byte
		input        []byte
		expectRemoved bool
	}{
		{
			name:         "prefix removed from input",
			prefix:       []byte("prefix:"),
			input:        []byte("prefix:data"),
			expectRemoved: true,
		},
		{
			name:         "no prefix in input",
			prefix:       []byte("prefix:"),
			input:        []byte("other:data"),
			expectRemoved: false,
		},
		{
			name:         "empty prefix",
			prefix:       []byte{},
			input:        []byte("data"),
			expectRemoved: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			receivedData := []byte{}
			transformer := &mockTransformer{
				decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
					receivedData = data
					return data, false, nil
				},
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: tt.prefix, Transformer: transformer},
			)

			ctx := context.Background()
			prefixTrans.TransformFromStorage(ctx, tt.input, nil)

			if tt.expectRemoved {
				// Prefix should have been removed
				if !bytes.HasPrefix(tt.input, tt.prefix) {
					// Input didn't have prefix, so transformer should have received original
					return
				}
				expectedData := tt.input[len(tt.prefix):]
				if !bytes.Equal(receivedData, expectedData) {
					t.Errorf("transformer received %q, want %q", receivedData, expectedData)
				}
			}
		})
	}
}

// TestContextInterface verifies that different Context implementations work correctly
func TestContextInterface(t *testing.T) {
	tests := []struct {
		name        string
		context     Context
		expectedLen int
	}{
		{
			name:        "DefaultContext with data",
			context:     DefaultContext([]byte("test")),
			expectedLen: 4,
		},
		{
			name:        "DefaultContext empty",
			context:     DefaultContext([]byte{}),
			expectedLen: 0,
		},
		{
			name:        "nil context",
			context:     nil,
			expectedLen: -1, // special case for nil
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.context == nil {
				// nil context is valid (no authentication data required)
				return
			}

			authData := tt.context.AuthenticatedData()
			if tt.expectedLen == 0 {
				if len(authData) != 0 {
					t.Errorf("AuthenticatedData length = %d, want 0", len(authData))
				}
			} else if len(authData) != tt.expectedLen {
				t.Errorf("AuthenticatedData length = %d, want %d", len(authData), tt.expectedLen)
			}
		})
	}
}

// TestTransformerChaining verifies that multiple transformers can be chained together
func TestTransformerChaining(t *testing.T) {
	// Create two transformers that will be applied in sequence
	transformer1 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			// ROT13-like transformation for testing
			result := make([]byte, len(data))
			for i, b := range data {
				result[i] = (b + 1) % 256
			}
			return result, nil
		},
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			result := make([]byte, len(data))
			for i, b := range data {
				result[i] = (b - 1) % 256
			}
			return result, false, nil
		},
	}

	transformer2 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			// Double each byte
			result := make([]byte, len(data)*2)
			for i, b := range data {
				result[2*i] = b
				result[2*i+1] = b
			}
			return result, nil
		},
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			result := make([]byte, len(data)/2)
			for i := 0; i < len(data); i += 2 {
				result[i/2] = data[i]
			}
			return result, false, nil
		},
	}

	original := []byte("test")
	ctx := context.Background()

	// Encrypt with transformer1
	enc1, err := transformer1.TransformToStorage(ctx, original, nil)
	if err != nil {
		t.Fatalf("transformer1 encryption failed: %v", err)
	}

	// Encrypt with transformer2
	enc2, err := transformer2.TransformToStorage(ctx, enc1, nil)
	if err != nil {
		t.Fatalf("transformer2 encryption failed: %v", err)
	}

	// Decrypt with transformer2
	dec2, _, err := transformer2.TransformFromStorage(ctx, enc2, nil)
	if err != nil {
		t.Fatalf("transformer2 decryption failed: %v", err)
	}

	// Decrypt with transformer1
	dec1, _, err := transformer1.TransformFromStorage(ctx, dec2, nil)
	if err != nil {
		t.Fatalf("transformer1 decryption failed: %v", err)
	}

	if !bytes.Equal(dec1, original) {
		t.Errorf("chained transformation failed: got %q, want %q", dec1, original)
	}
}

// TestPrefixTransformerMultiplePrefixes verifies behavior with multiple prefixes
func TestPrefixTransformerMultiplePrefixes(t *testing.T) {
	transformer1 := &mockTransformer{
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			return []byte("result1"), false, nil
		},
	}
	transformer2 := &mockTransformer{
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			return []byte("result2"), false, nil
		},
	}
	transformer3 := &mockTransformer{
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			return []byte("result3"), false, nil
		},
	}

	prefixes := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
		PrefixTransformer{Prefix: []byte("third:"), Transformer: transformer3},
	)

	tests := []struct {
		name   string
		input  []byte
		expect []byte
	}{
		{"match first prefix", []byte("first:data"), []byte("result1")},
		{"match second prefix", []byte("second:data"), []byte("result2")},
		{"match third prefix", []byte("third:data"), []byte("result3")},
	}

	ctx := context.Background()
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result, _, err := prefixes.TransformFromStorage(ctx, tt.input, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}
			if !bytes.Equal(result, tt.expect) {
				t.Errorf("result = %q, want %q", result, tt.expect)
			}
		})
	}
}

// TestPrefixTransformerFirstTransformerUsedForStorage verifies that the first transformer is used for writes
func TestPrefixTransformerFirstTransformerUsedForStorage(t *testing.T) {
	transformer1Called := false
	transformer2Called := false

	transformer1 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			transformer1Called = true
			return []byte("encrypted-by-1"), nil
		},
	}
	transformer2 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			transformer2Called = true
			return []byte("encrypted-by-2"), nil
		},
	}

	prefixes := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
	)

	ctx := context.Background()
	result, err := prefixes.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if !transformer1Called {
		t.Error("first transformer should be called for TransformToStorage")
	}
	if transformer2Called {
		t.Error("second transformer should not be called for TransformToStorage")
	}

	// The result should be prefixed with the first transformer's prefix
	if !bytes.HasPrefix(result, []byte("first:")) {
		t.Errorf("result should be prefixed with 'first:', got %q", result)
	}
}

// TestEmptyDataTransformation verifies handling of empty data
func TestEmptyDataTransformation(t *testing.T) {
	transformer := &mockTransformer{}
	ctx := context.Background()

	encrypted, err := transformer.TransformToStorage(ctx, []byte{}, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	decrypted, _, err := transformer.TransformFromStorage(ctx, encrypted, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if len(decrypted) != 0 {
		t.Errorf("expected empty result, got %q", decrypted)
	}
}

// TestDataCtxPropagation verifies that the data context is passed correctly through transformations
func TestDataCtxPropagation(t *testing.T) {
	var receivedCtx Context

	transformer := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			return data, nil
		},
		decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
			return data, false, nil
		},
	}

	ctx := context.Background()
	dataCtx := DefaultContext([]byte("test-authenticated-data"))

	transformer.TransformToStorage(ctx, []byte("data"), dataCtx)
	transformer.TransformFromStorage(ctx, []byte("data"), dataCtx)

	receivedCtx = dataCtx

	if receivedCtx == nil {
		t.Error("DataCtx should not be nil after transformation")
	}
}

