// TestPrefixTransformerPrefixHandling verifies prefix removal during transformation
func TestPrefixTransformerPrefixHandling(t *testing.T) {
	tests := []struct {
		name         string
		prefix       []byte
		input        []byte
		expectRemoved bool
	}{
		{
			name:         "prefix removed from input",
			prefix:       []byte("prefix:"),
			input:        []byte("prefix:data"),
			expectRemoved: true,
		},
		{
			name:         "no prefix in input",
			prefix:       []byte("prefix:"),
			input:        []byte("other:data"),
			expectRemoved: false,
		},
		{
			name:         "empty prefix",
			prefix:       []byte{},
			input:        []byte("data"),
			expectRemoved: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			receivedData := []byte{}
			transformer := &mockTransformer{
				decryptFunc: func(ctx context.Context, data []byte) ([]byte, bool, error) {
					receivedData = data
					return data, false, nil
				},
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: tt.prefix, Transformer: transformer},
			)

			ctx := context.Background()
			prefixTrans.TransformFromStorage(ctx, tt.input, nil)

			if tt.expectRemoved {
				// Prefix should have been removed
				if !bytes.HasPrefix(tt.input, tt.prefix) {
					// Input didn't have prefix, so transformer should have received original
					return
				}
				expectedData := tt.input[len(tt.prefix):]
				if !bytes.Equal(receivedData, expectedData) {
					t.Errorf("transformer received %q, want %q", receivedData, expectedData)
				}
			}
		})
	}
}

