// TestPrefixTransformerFirstTransformerUsedForStorage verifies that the first transformer is used for writes
func TestPrefixTransformerFirstTransformerUsedForStorage(t *testing.T) {
	transformer1Called := false
	transformer2Called := false

	transformer1 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			transformer1Called = true
			return []byte("encrypted-by-1"), nil
		},
	}
	transformer2 := &mockTransformer{
		encryptFunc: func(ctx context.Context, data []byte) ([]byte, error) {
			transformer2Called = true
			return []byte("encrypted-by-2"), nil
		},
	}

	prefixes := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
	)

	ctx := context.Background()
	result, err := prefixes.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if !transformer1Called {
		t.Error("first transformer should be called for TransformToStorage")
	}
	if transformer2Called {
		t.Error("second transformer should not be called for TransformToStorage")
	}

	// The result should be prefixed with the first transformer's prefix
	if !bytes.HasPrefix(result, []byte("first:")) {
		t.Errorf("result should be prefixed with 'first:', got %q", result)
	}
}

